WITH history_log AS (select * from dev_history_log WHERE history_id in ( select max(history_id) from dev_history_log where config_id = #{configId} and pack_num = #{packNum}
and item_code in
#{itemCode}
group by pack_num, item_code ) ) select l.history_id, l.config_id, l.pack_num, l.item_code, l.value_info, l.data_info, l.create_time, l.update_time, a.name as itemName, c.name as configName, d.status as alarmStatus from history_log l join dev_config c on l.config_id = c.config_id and c.status = 0 join dev_config_attribute a on l.config_id = a.config_id and l.item_code = a.code and (l.pack_num is null or l.pack_num = a.pack_num) and a.status = 0 left join dev_alarm_log d on l.config_id = d.config_id and l.item_code = d.item_code and (l.pack_num is null or l.pack_num = d.pack_num) and d.status = 1 WHERE 1 = 1 and d.status = #{alarmStatus}

select
l.history_id, l.config_id, l.pack_num, l.item_code, l.value_info, l.data_info, l.create_time, l.update_time
from dev_history_log l

     and l.config_id = #{configId}
     and l.pack_num = #{packNum}
     and l.item_code = #{itemCode}

        and l.item_code in

            #{itemCode}



        and strftime('%Y-%m-%d %H:%M:%S', l.create_time) >= strftime('%Y-%m-%d %H:%M:%S', #{params.beginTime})


        and strftime('%Y-%m-%d %H:%M:%S', l.create_time) <= strftime('%Y-%m-%d %H:%M:%S', #{params.endTime})


order by l.history_id desc limit 10000

select
l.history_id, l.config_id, l.pack_num, l.item_code, l.value_info, l.data_info, l.create_time, l.update_time
from dev_history_log l

     and l.config_id = #{configId}
     and l.pack_num = #{packNum}
     and l.item_code = #{itemCode}

        and l.item_code in

            #{itemCode}


     and l.data_info like '%'||#{dataInfo}||'%'

        and strftime('%Y-%m-%d %H:%M:%S', l.create_time) >= strftime('%Y-%m-%d %H:%M:%S', #{params.beginTime})


        and strftime('%Y-%m-%d %H:%M:%S', l.create_time) <= strftime('%Y-%m-%d %H:%M:%S', #{params.endTime})


order by l.history_id desc



     and config_id = #{configId}
     and pack_num = #{packNum}
     and item_code = #{itemCode}

order by l.history_id desc limit 1

